#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int num_iterations,
    __global const float *power,
    __global const float *temp_in,
    __global float *temp_out,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    // Calculate total number of blocks based on grid dimensions
    int blockCols = (col + BLOCK_SIZE - 1) / BLOCK_SIZE;
    int blockRows = (row + BLOCK_SIZE - 1) / BLOCK_SIZE;

    // Get block IDs using standard OpenCL function
    int block_id_x = get_group_id(0);
    int block_id_y = get_group_id(1);

    // Calculate chunk index
    int chunk = block_id_y * blockCols + block_id_x;

    int chunks_in_row = blockCols;
    int chunks_in_col = blockRows;

    int r_start = BLOCK_SIZE * (chunk / chunks_in_col);
    int c_start = BLOCK_SIZE * (chunk % chunks_in_row);
    int r_end = r_start + BLOCK_SIZE > row ? row : r_start + BLOCK_SIZE;
    int c_end = c_start + BLOCK_SIZE > col ? col : c_start + BLOCK_SIZE;

    int local_r = get_local_id(1);
    int local_c = get_local_id(0);

    // Boundary check for the block
    if (r_start + local_r >= r_end || c_start + local_c >= c_end) {
        return;
    }

    int r = r_start + local_r;
    int c = c_start + local_c;
    int idx = r * col + c;

    float delta;

    bool is_r0 = (r == 0);
    bool is_r_last = (r == row - 1);
    bool is_c0 = (c == 0);
    bool is_c_last = (c == col - 1);

    if (is_r0 && is_c0) {
        // Top-left corner
        delta = Cap_1 * (power[0] +
            (temp_in[1] - temp_in[0]) * Rx_1 +
            (temp_in[col] - temp_in[0]) * Ry_1 +
            (amb_temp - temp_in[0]) * Rz_1);
    }
    else if (is_r0 && is_c_last) {
        // Top-right corner
        delta = Cap_1 * (power[c] +
            (temp_in[c-1] - temp_in[c]) * Rx_1 +
            (temp_in[c+col] - temp_in[c]) * Ry_1 +
            (amb_temp - temp_in[c]) * Rz_1);
    }
    else if (is_r_last && is_c_last) {
        // Bottom-right corner
        delta = Cap_1 * (power[idx] +
            (temp_in[idx-1] - temp_in[idx]) * Rx_1 +
            (temp_in[(r-1)*col+c] - temp_in[idx]) * Ry_1 +
            (amb_temp - temp_in[idx]) * Rz_1);
    }
    else if (is_r_last && is_c0) {
        // Bottom-left corner
        delta = Cap_1 * (power[r*col] +
            (temp_in[r*col+1] - temp_in[r*col]) * Rx_1 +
            (temp_in[(r-1)*col] - temp_in[r*col]) * Ry_1 +
            (amb_temp - temp_in[r*col]) * Rz_1);
    }
    else if (is_r0) {
        // Top edge
        delta = Cap_1 * (power[c] +
            (temp_in[c+1] + temp_in[c-1] - 2.0f * temp_in[c]) * Rx_1 +
            (temp_in[col+c] - temp_in[c]) * Ry_1 +
            (amb_temp - temp_in[c]) * Rz_1);
    }
    else if (is_c_last) {
        // Right edge
        delta = Cap_1 * (power[idx] +
            (temp_in[(r+1)*col+c] + temp_in[(r-1)*col+c] - 2.0f * temp_in[idx]) * Ry_1 +
            (temp_in[idx-1] - temp_in[idx]) * Rx_1 +
            (amb_temp - temp_in[idx]) * Rz_1);
    }
    else if (is_r_last) {
        // Bottom edge
        delta = Cap_1 * (power[idx] +
            (temp_in[idx+1] + temp_in[idx-1] - 2.0f * temp_in[idx]) * Rx_1 +
            (temp_in[(r-1)*col+c] - temp_in[idx]) * Ry_1 +
            (amb_temp - temp_in[idx]) * Rz_1);
    }
    else if (is_c0) {
        // Left edge
        delta = Cap_1 * (power[r*col] +
            (temp_in[(r+1)*col] + temp_in[(r-1)*col] - 2.0f * temp_in[r*col]) * Ry_1 +
            (temp_in[r*col+1] - temp_in[r*col]) * Rx_1 +
            (amb_temp - temp_in[r*col]) * Rz_1);
    }
    else {
        // Interior
        delta = Cap_1 * (power[idx] +
            (temp_in[(r+1)*col+c] + temp_in[(r-1)*col+c] - 2.0f * temp_in[idx]) * Ry_1 +
            (temp_in[idx+1] + temp_in[idx-1] - 2.0f * temp_in[idx]) * Rx_1 +
            (amb_temp - temp_in[idx]) * Rz_1);
    }

    temp_out[idx] = temp_in[idx] + delta;
}
